mapper.select:
select * from agent_commission_final_report
where agent_id = #{agentId}
order by created_time desc limit 1

select t1.*
FROM
`agent_commission_final_report` t1
where
 t1.agent_id = #{vo.agentId}

    AND  t1.start_time  >=  #{vo.startTime}


    AND t1.end_time  <=  #{vo.endTime}


    and t1.status IN

        #{value}


order by end_time desc limit 1

SELECT t1.agent_account agentAccount, sum(t1.active_number) activeValidNumber, sum(t1.new_valid_number) newActiveNumber, sum(t1.user_win_loss_total) userWinLossTotal, sum(t1.venue_fee) venueFee, sum(t1.transfer_amount) discountUsed, sum(t1.access_fee) accessFee, sum(t1.discount_amount) discountAmount, sum(t1.vip_amount) vipAmount, sum(t1.valid_bet_amount) validBetAmount, sum(t1.active_number) activeValidNumber, sum(t1.new_valid_number) newActiveNumber, sum(t1.net_win_loss) netWinLoss, sum(t1.last_month_remain) lastMonthRemain, sum(t1.commission_amount) commissionAmount, sum(t1.adjust_amount) adjustAmount, sum(t1.review_adjust_amount) reviewAdjustAmount, sum(t1.bet_win_loss) betWinLoss, sum(t1.tips_amount) tipsAmount FROM `agent_commission_final_report` t1 where t1.site_code = #{vo.siteCode}
and t1.agent_id IN
#{value}
and t1.status IN
#{value}
AND t1.agent_account = #{vo.agentAccount}
AND t1.start_time >= #{vo.startTime}
AND t1.end_time <= #{vo.endTime}
group by t1.agent_account

SELECT t1.agent_account agentAccount, sum(t1.active_number) activeValidNumber, sum(t1.new_valid_number) newActiveNumber, sum(t1.user_win_loss_total) userWinLossTotal, sum(t1.venue_fee) venueFee, sum(t1.transfer_amount) discountUsed, sum(t1.access_fee) accessFee, sum(t1.discount_amount) discountAmount, sum(t1.vip_amount) vipAmount, sum(t1.valid_bet_amount) validBetAmount, sum(t1.active_number) activeValidNumber, sum(t1.new_valid_number) newActiveNumber, sum(t1.net_win_loss) netWinLoss, sum(t1.last_month_remain) lastMonthRemain, sum(t1.commission_amount) commissionAmount, sum(t1.adjust_amount) adjustAmount, sum(t1.review_adjust_amount) reviewAdjustAmount, sum(t1.bet_win_loss) betWinLoss, sum(t1.tips_amount) tipsAmount FROM `agent_commission_final_report` t1 where t1.site_code = #{vo.siteCode}
and t1.agent_id IN
#{value}
AND t1.agent_account = #{vo.agentAccount}
AND t1.end_time >= #{vo.startTime}
AND t1.start_time <= #{vo.endTime}
group by t1.agent_account

SELECT * FROM
`agent_commission_final_report`
WHERE agent_id = #{vo.agentId}
AND (
(
start_time  <=  #{vo.startTime}
AND end_time  >=  #{vo.startTime}
)
OR (
start_time  <=  #{vo.endTime}
AND end_time  >=  #{vo.endTime}
)
)
